//! NIST FIPS 203 ML-KEM-768 Test Vectors
//!
//! Test vectors from NIST ACVP-Server:
//! https://github.com/usnistgov/ACVP-Server/tree/master/gen-val/json-files
//!
//! These tests validate our ML-KEM-768 implementation against official
//! NIST Algorithm Validation Program (ACVP) test vectors.

const std = @import("std");
const mlkem = @import("ml_kem_api.zig");

// ============================================================================
// NIST ACVP Test Vector: ML-KEM-768 EncapDecap (tcId: 26)
// Source: ML-KEM-encapDecap-FIPS203/internalProjection.json
// ============================================================================

const nist_ek_hex = "";

const nist_dk_hex = "";

const nist_ciphertext_hex = "";

const nist_shared_secret_hex = "B2425299020BCF563B8EBE0512F0479941335A75A32B8D10BFF60E5548B64672";

// ============================================================================
// Helper Functions
// ============================================================================

fn hexCharToNibble(c: u8) u8 {
    return switch (c) {
        '0'...'9' => c - '0',
        'A'...'F' => c - 'A' + 10,
        'a'...'f' => c - 'a' + 10,
        else => unreachable,
    };
}

fn hexToBytes(comptime hex: []const u8) [hex.len / 2]u8 {
    @setEvalBranchQuota(50000);
    var result: [hex.len / 2]u8 = undefined;
    for (0..result.len) |i| {
        const hi = hexCharToNibble(hex[i * 2]);
        const lo = hexCharToNibble(hex[i * 2 + 1]);
        result[i] = (hi << 4) | lo;
    }
    return result;
}

// ============================================================================
// Tests
// ============================================================================

test "NIST ACVP ML-KEM-768 Decapsulation" {
    // Parse NIST test vector
    const dk_bytes = comptime hexToBytes(nist_dk_hex);
    const ct_bytes = comptime hexToBytes(nist_ciphertext_hex);
    const expected_k = comptime hexToBytes(nist_shared_secret_hex);

    // Construct decapsulation key
    var dk: mlkem.DecapsulationKey768 = undefined;
    @memcpy(&dk.data, &dk_bytes);

    // Construct ciphertext
    var ct: mlkem.Ciphertext768 = undefined;
    @memcpy(&ct.data, &ct_bytes);

    // Perform decapsulation
    const computed_k = mlkem.decaps768(&dk, &ct);

    // Verify against NIST expected value
    try std.testing.expectEqualSlices(u8, &expected_k, &computed_k);
}

test "NIST key sizes match FIPS 203" {
    // FIPS 203 specifies these sizes for ML-KEM-768
    try std.testing.expectEqual(@as(usize, 1184), @sizeOf(mlkem.EncapsulationKey768));
    try std.testing.expectEqual(@as(usize, 2400), @sizeOf(mlkem.DecapsulationKey768));
    try std.testing.expectEqual(@as(usize, 1088), @sizeOf(mlkem.Ciphertext768));
    try std.testing.expectEqual(@as(usize, 32), @sizeOf(mlkem.SharedSecret));
}

test "NIST vector key structure validation" {
    // Verify the NIST keys have correct sizes
    const ek_bytes = comptime hexToBytes(nist_ek_hex);
    const dk_bytes = comptime hexToBytes(nist_dk_hex);
    const ct_bytes = comptime hexToBytes(nist_ciphertext_hex);
    const k_bytes = comptime hexToBytes(nist_shared_secret_hex);

    try std.testing.expectEqual(@as(usize, 1184), ek_bytes.len);
    try std.testing.expectEqual(@as(usize, 2400), dk_bytes.len);
    try std.testing.expectEqual(@as(usize, 1088), ct_bytes.len);
    try std.testing.expectEqual(@as(usize, 32), k_bytes.len);
}

test "ML-KEM-768 round-trip correctness" {
    // Generate fresh key pair
    const kp = try mlkem.keyGen768();

    // Encapsulate
    const enc = try mlkem.encaps768(&kp.ek);

    // Decapsulate
    const dec_k = mlkem.decaps768(&kp.dk, &enc.c);

    // Shared secrets must match
    try std.testing.expectEqualSlices(u8, &enc.K, &dec_k);
}

test "ML-KEM-768 implicit rejection" {
    // Generate two different key pairs
    const kp1 = try mlkem.keyGen768();
    const kp2 = try mlkem.keyGen768();

    // Encapsulate with kp1's public key
    const enc = try mlkem.encaps768(&kp1.ek);

    // Decapsulate with kp2's private key (wrong key)
    const wrong_k = mlkem.decaps768(&kp2.dk, &enc.c);

    // Should NOT match - implicit rejection should produce different secret
    try std.testing.expect(!std.mem.eql(u8, &enc.K, &wrong_k));

    // The wrong_k should still be 32 bytes (deterministic pseudorandom output)
    try std.testing.expectEqual(@as(usize, 32), wrong_k.len);
}

test "ML-KEM-768 ciphertext modification detection" {
    // Generate key pair
    const kp = try mlkem.keyGen768();

    // Encapsulate
    const enc = try mlkem.encaps768(&kp.ek);

    // Modify ciphertext
    var modified_ct = enc.c;
    modified_ct.data[0] ^= 0xFF;

    // Decapsulate modified ciphertext
    const modified_k = mlkem.decaps768(&kp.dk, &modified_ct);

    // Should NOT match original secret (implicit rejection)
    try std.testing.expect(!std.mem.eql(u8, &enc.K, &modified_k));
}
